import type { BwCashflowModel } from "@dfp/bw-sdk-bw-cashflow";

import type { BalanceQuality } from "../../types/cashflow.types.ts";

export type CashFlowResponse =
  BwCashflowModel["getCashFlowAndBalanceStates"]["response"];
type CashFlowStates = NonNullable<CashFlowResponse["cashFlowStates"]>;
type SumArray = NonNullable<CashFlowStates["sumArray"]>;
type SumArrayItem = SumArray[number];
type IncomeCategorySum = NonNullable<SumArrayItem["incomeCategorySum"]>;
type ApiCategoryType = IncomeCategorySum[number]["category"];

export type CategoryType = ApiCategoryType;

/**
 * Represents a single period column in the cashflow table
 */
export type CashflowPeriod = {
  id: string;
  /** Date of the period (YYYY-MM-DD) */
  dateFrom: string;
  dateTo: string;
  /** Total income for this period */
  income: number;
  /** Total costs for this period */
  costs: number;
  /** Net change (income - costs) */
  netBalance: number;
  /** Final balance at end of period, including quality information when available */
  finalBalance: {
    value: number;
    balanceQuality: BalanceQuality;
  } | null;
  incomeCategories: Map<CategoryType, number>;
  costsCategories: Map<CategoryType, number>;
  progressPercentage?: number;
  transactionCount?: number;
};

/**
 * Complete data structure for the cashflow table
 */
export type CashflowTableData = {
  periods: CashflowPeriod[];
  granularity: "1D" | "1W" | "1M";
  categories: {
    income: CategoryType[];
    costs: CategoryType[];
  };
};

export type CategoryFilter = {
  income: CategoryType[];
  costs: CategoryType[];
};

export type CategoryFilterSection = "income" | "costs";

export type CategoryOption = {
  value: CategoryType;
  label: string;
};

export type CategoryFilterState = {
  categoryFilter: CategoryFilter;
  setCategoryFilter: (filter: CategoryFilter) => void;
  allCategories: CategoryOption[];
  allCategoryValues: CategoryType[];
  isFiltered: boolean;
  totalSelected: number;
  totalAvailable: number;
};

export type CashflowTableCellProps = {
  value: number;
  columnIndex: number;
  dateFrom: string;
  isBold?: boolean;
  /** Optional progress percentage to display as a bar */
  progressPercentage?: number;
  /** Color mode for value display:
   * - "balance": red for negative, green for positive (Net Balance)
   * - "final": red for negative only, neutral for positive/zero (Final Balance)
   * - "none": always neutral color (Income, Costs, all categories)
   * Default: "none"
   */
  colorMode?: "balance" | "final" | "none";
  /** Optional click handler. When provided, replaces the default column toggle behavior. */
  onClick?: () => void;
};

import { ReactNode, createContext, useContext, useMemo } from "react";

import type { Currency, Interval } from "../../types/cashflow.types.ts";
import type {
  CashFlowResponse,
  CashflowTableData,
  CategoryFilterState,
} from "../types/index.ts";
import { transformCashflowData } from "../utils/index.ts";

export type CashflowTableContextValue = {
  data: CashflowTableData | null;
  interval: Interval;
  currency: Currency;
  bankAccountIdArray: string[];
} & CategoryFilterState;

const CashflowTableContext = createContext<CashflowTableContextValue | null>(
  null,
);

export function useCashflowTable() {
  const context = useContext(CashflowTableContext);
  if (!context) {
    throw new Error(
      "useCashflowTable must be used within a CashflowTable provider",
    );
  }
  return context;
}

type CashflowTableProviderProps = {
  children: ReactNode;
  data: CashFlowResponse | undefined;
  interval: Interval;
  currency: Currency;
  bankAccountIdArray: string[];
  categoryFilterState: CategoryFilterState;
};

export function CashflowTableProvider({
  children,
  data,
  interval,
  currency,
  bankAccountIdArray,
  categoryFilterState,
}: CashflowTableProviderProps) {
  const tableData = useMemo(() => {
    if (!data) {
      return null;
    }
    return transformCashflowData(data);
  }, [data]);

  const context = useMemo(
    () => ({
      data: tableData,
      interval,
      currency,
      bankAccountIdArray,
      ...categoryFilterState,
    }),
    [tableData, interval, currency, bankAccountIdArray, categoryFilterState],
  );

  return (
    <CashflowTableContext.Provider value={context}>
      {children}
    </CashflowTableContext.Provider>
  );
}

