export function CashflowTableSection({ isLoading }: CashflowTableSectionProps) {
  const { tt } = useTT();
  const { data } = useCashflowTable();

  if (isLoading) {
    return <CashflowTableSkeleton />;
  }

  if ((data?.periods.length ?? 0) === 0) {
    return (
      <EmptyState
        icon={<IconBarChart03 />}
        title={tt("cashflowTable.noDataTitle")}
        subtitle={tt("cashflowTable.noDataMessage")}
      />
    );
  }
  return (
    <CategoryDetailPopoverProvider>
      <CashflowTable />
    </CategoryDetailPopoverProvider>
  );
}

